public void testParseProperValidPositive() {
    String source = "2 3 / 4";
    try {
        Fraction c = properFormat.parse(source);
        assertEquals(11, c.getNumerator());
        assertEquals(4, c.getDenominator());
    } catch (ParseException ex) {
        fail("Should parse valid proper fraction.");
    }
}

public void testParseProperNegativeWhole() {
    String source = "-2 3 / 4";
    try {
        Fraction c = properFormat.parse(source);
        assertEquals(-11, c.getNumerator());
        assertEquals(4, c.getDenominator());
    } catch (ParseException ex) {
        fail("Should parse valid negative proper fraction.");
    }
}

public void testParseProperWithoutSlash() {
    String source = "2 3";
    try {
        Fraction c = properFormat.parse(source);
        assertEquals(3, c.getNumerator());
        assertEquals(1, c.getDenominator());
    } catch (ParseException ex) {
        fail("Should parse fraction without slash.");
    }
}
